import numpy as np

def apply_pbc(r, L):
    """
    Wrap position into central box [-L/2, L/2).
    """
    return r - L * np.floor(r / L + 0.5)

def minimum_image_distance(r1, r2, L):
    """
    Compute distance using minimum image convention.
    """
    dr = r2 - r1
    dr = apply_pbc(dr, L)  # Wrap difference vector
    return np.sqrt(np.sum(dr**2))
